map_status() {
  case "$1" in
    open) echo "open" ;;
    backlog) echo "backlog" ;;
    closed|cancelled|done|folded) echo "closed" ;;
    pending|deferred|parked|monitoring|Grooming|"") echo "open" ;;
    in-progress|in_progress) echo "in_progress" ;;
    *) echo "" ;;
  esac
}

