map_status() {
  case "$1" in
    open|backlog|closed|cancelled|done|pending|deferred|parked|monitoring|in-progress|in_progress|folded|Grooming) ;;
    *) echo ""; return ;;
  esac
  case "$1" in
    open) echo "open" ;;
    backlog) echo "backlog" ;;
    closed|cancelled|done|folded) echo "closed" ;;
    pending|deferred|parked|monitoring) echo "open" ;;
    in-progress|in_progress) echo "in_progress" ;;
    Grooming) echo "open" ;;
    *) echo "" ;;
  esac
}

